import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as s}from"./nyalra_no_mono-8344e451.js";import{_ as p,W as c,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const u={},f=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/8b59fd154375703d2b7b09a91526118a.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>尽管我想警告说：「停下来！只是妄加评论，就会使你的账号变得低劣不堪！」 但实际上，这样提醒他人本身也属于「妄加评论」，本来我就不需要特意回复在timeline上经常看到的人。</p><p>但是，我仍然有这种念头。每天SNS上都有令人不安的网络新闻和八卦。当我在虚拟世界中漫无目的地浏览时，我会不自觉地希望对这些事情说上一句。基本上，因为对方通常不会回应，所以这只是一种轻松减压的方式，可以从远处快速发表一句话来释放压力，这在严酷的现代社会可能是必要的。</p><p>然而！然而，我仍然认为：「啊，这个人又要专门提到了与他无关的事情！」。大多数妄加评论都带有傲慢的口吻。毕竟，通常这种行为是用来嘲笑犯错的人，或者甚至更直接地谩骂他们的。每当网红引起争议时，只需发个推文说「这些曾经支持这位名人的粉丝也不咋样啊……」，您的地位就能一下子高于某些群体。如果再加入一些具有创意的黑色幽默，就会变得更加完美。在流行的内容中添加「黑色笑话」，这个账户就如鱼得水。</p><p>我懂，我懂啊。乐子。因为你可以轻松地对那些本来无法触及的人捅一刀。如果推文得到了良好的传播，您的粉丝也会增加，同样的人也会聚集在一起。但正因如此，最好还是不要这样做。黑暗的推文只是一瞬间的兴奋剂。被称赞说「这个账号可以做出富有批评性和嘲笑的推文」，这只是陷阱。这是那些试图通过你的账号来发泄的坏人们巧妙策划的。</p><p>这已经没有办法。越多地浏览SNS，你就越想对某些事件发表一番言论。你会想要加入进去。</p><p>但是，可以肯定的是……绝对的是，这样做会使你沾染黑暗，变成腐烂的「不明物体」。人本来就只需要关心自己能够触及的范围。与其发布推文，嘲笑一个陌生人的过失，弗如给正在为弹珠机输掉而哭泣的朋友发条信息，告诉他「我请客吃牛丼吧」，这样要好1000倍。</p><p>如果你开始想对与你无关的事情妄加评论并感到愉悦的话，这意味着你的大脑已经记住了「妄加评论」的滋味。在那一刻，关闭手机，躺5分钟吧。你会发现，屏幕那边的噪音对你来说已经无关紧要了。不要让廉价的妄加评论污染你的灵魂。人们应该更多地将精力用来应对即将到来的事情。</p><hr><p><img src="'+s+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/774458e79908536033a0fba8613d4da8.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【爱丽丝的模型和玩偶】这是以《不思議の国のアリス》为主题的立体物品角落。无论如何，御宅族迟早都会对爱丽丝产生憧憬。那种纯真无垢的少女光芒，实在是太狡猾了。</p></blockquote>',11);function g(x,N){const n=a("ExternalLinkIcon"),r=a("RouterLink");return c(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("第29回／言及するだけアカウントが腐る"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_28.html"},{default:m(()=>[t("【奈亚拉面壁自语】第28回｜Discord管理格斗记录【230530】")]),_:1})])]),b])}const V=p(u,[["render",g],["__file","nyalra_kb_29.html.vue"]]);export{V as default};
